chart.options:
chart: {
  height: 350,
  type: 'line',
  stacked: true,
  stackOnlyBar: false,
},
plotOptions: {
  bar: {
    columnWidth: '70%'
  }
},
dataLabels: {
  enabled: true,
  enabledOnSeries: [10]
},
title: {
  text: 'Regional & Online Sales Mix'
},
xaxis: {
  categories: [2017, 2018, 2019, 2020, 2021, 2022, 2023, 2024]
},
yaxis: [
{
  seriesName: ['North · Electronics','North · Apparel','North · Home',
               'South · Electronics','South · Apparel','South · Home'],
  axisTicks: {
    show: true,
    color: '#008FFB'
  },
  axisBorder: {
    show: true,
    color: '#008FFB'
  },
  title: {
    text: "Regional Sales ($k)",
    style: {
      color: '#008FFB'
    }
  },
  labels: {
    style: {
      colors: ['#008FFB']
    }
  }
},{
  opposite: true,
  seriesName: ['Online · Direct', 'Online · Marketplace'],
  axisTicks: {
    show: true,
    color: '#78909C'
  },
  axisBorder: {
    show: true,
    color: '#78909C'
  },
  title: {
    text: "Online Sales ($k)",
    style: {
      color: '#78909C'
    }
  }
},{
  seriesName: ['Forecast','Budget'],
  labels: {
    style: {
      colors: ['#88AA88']
    }
  },
  axisTicks: {
    show: true,
    color: '#88AA88'
  },
  axisBorder: {
    show: true,
    color: '#88AA88'
  },
  title: {
    text: "Planning ($k)",
    style: {
      color: '#88AA88'
    }
  }
},{
  opposite: true,
  seriesName: 'Growth Index',
  labels: {
    style: {
      colors: ['#78909C']
    }
  },
  axisTicks: {
    show: true,
    color: '#78909C'
  },
  axisBorder: {
    show: true,
    color: '#78909C'
  },
  title: {
    text: "Growth Index",
    style: {
      color: '#78909C'
    }
  }
}
],
fill: {
type: 'gradient',
gradient: {
  shade: 'light'
}
},
stroke: {
width: [4,4,4,4,4,4,4,4,1,1,3],
colors: ['rgba(0,0,0,0)','rgba(0,0,0,0)','rgba(0,0,0,0)',
         'rgba(0,0,0,0)','rgba(0,0,0,0)','rgba(0,0,0,0)',
         'rgba(0,0,0,0)','rgba(0,0,0,0)',
         '#fff','#fff',
         '#222222'],
curve: ['','','','','','','','','stepline','stepline','straight']
},
colors: ['#00D8B6','#008FFB','#FEB019',
       '#FF4560','#775DD0',"#95C11F",
       '#DDDDDD','#888888',
       '#88AA88','#DDEEDD',
       '#AAAAAA'],
tooltip: {
shared: true
}

